# SAML namespace mappings
NAMESPACES = {
    'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
    'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
    'ds': 'http://www.w3.org/2000/09/xmldsig#'
}

def parse_saml_response(saml_response_base64):
    """Parse SAML response and extract assertions"""
    try:
        saml_xml = base64.b64decode(saml_response_base64)
        root = ET.fromstring(saml_xml)
        
        assertions = root.findall('.//saml:Assertion', NAMESPACES)
        
        if not assertions:
            return None, "No assertions found in SAML response"
        
        user_data = {}
        
        for assertion in assertions:
            subject = assertion.find('.//saml:Subject/saml:NameID', NAMESPACES)
            if subject is not None:
                user_data['name_id'] = subject.text
                user_data['name_id_format'] = subject.get('Format', '')
            
            conditions = assertion.find('.//saml:Conditions', NAMESPACES)
            if conditions is not None:
                user_data['not_before'] = conditions.get('NotBefore')
                user_data['not_on_or_after'] = conditions.get('NotOnOrAfter')
            
            attribute_statements = assertion.findall('.//saml:AttributeStatement/saml:Attribute', NAMESPACES)
            
            for attribute in attribute_statements:
                attr_name = attribute.get('Name')
                attr_values = attribute.findall('saml:AttributeValue', NAMESPACES)
                
                if len(attr_values) == 1:
                    user_data[attr_name] = attr_values[0].text
                else:
                    user_data[attr_name] = [val.text for val in attr_values]
            
            authn_statement = assertion.find('.//saml:AuthnStatement', NAMESPACES)
            if authn_statement is not None:
                user_data['authn_instant'] = authn_statement.get('AuthnInstant')
                user_data['session_index'] = authn_statement.get('SessionIndex')
                
                authn_context = authn_statement.find('.//saml:AuthnContext/saml:AuthnContextClassRef', NAMESPACES)
                if authn_context is not None:
                    user_data['authn_context'] = authn_context.text
        
        return user_data, None
        
    except ET.ParseError as e:
        return None, f"XML Parse Error: {str(e)}"
    except Exception as e:
        return None, f"Error parsing SAML response: {str(e)}"

def validate_assertion_conditions(user_data):
    """Validate time-based conditions in the assertion"""
    if 'not_before' in user_data and 'not_on_or_after' in user_data:
        try:
            not_before = datetime.fromisoformat(user_data['not_before'].replace('Z', '+00:00'))
            not_on_or_after = datetime.fromisoformat(user_data['not_on_or_after'].replace('Z', '+00:00'))
            current_time = datetime.now(not_before.tzinfo)
            
            if current_time < not_before or current_time >= not_on_or_after:
                return False, "Assertion conditions not valid for current time"
        except:
            pass
    
    return True, None

